import os
import sys
import tarfile
import zipfile
import shutil
import subprocess

def backup(directory, format):
    # Check if the directory exists
    if not os.path.exists(directory):
        print("Error: Directory does not exist")
        return
    
    # Check if the format is supported
    if format not in ["tar.gz", "tar.bz2", "zip", "7z"]:
        print("Error: Unsupported compression format")
        return
    
    # Create the archive file name
    filename = f"{directory}.{format}"
    
    # Check if the file already exists
    if os.path.exists(filename):
        print("Error: File already exists")
        return
    
    # Create the archive
    if format == "tar.gz":
        with tarfile.open(filename, "w:gz") as tar:
            tar.add(directory)
    elif format == "tar.bz2":
        with tarfile.open(filename, "w:bz2") as tar:
            tar.add(directory)
    elif format == "zip":
        with zipfile.ZipFile(filename, "w", compression=zipfile.ZIP_DEFLATED) as zip:
            zip.write(directory)
    elif format == "7z":
        # Use the 7-Zip command line tool to create the archive
        subprocess.run(["7z", "a", "-t7z", filename, directory])
    
    # Print a success message
    print("Backup successful")

# Test the script with different inputs
backup("/path/to/directory", "tar.gz")
backup("/path/to/directory", "tar.bz2")
backup("/path/to/directory", "zip")
backup("/path/to/directory", "7z")

# Handle errors gracefully
try:
    backup("/path/to/nonexistent/directory", "tar.gz")
except Exception as e:
    print(f"Error: {e}")